import type { HTMLAttributes, ReactNode } from 'react';
import React from 'react';

interface RatingItemProps extends HTMLAttributes<HTMLDivElement> {
	index: number;
	children: ReactNode;
	onChange?: (index) => void;
}

export const RatingItem = ({ index, children, onChange, ...props }: RatingItemProps) => (
	<div
		role="button"
		tabIndex={onChange ? 0 : undefined}
		className="dsb_rating__select__item"
		{...props}
		onClick={() => {
			onChange?.(index);
		}}
		onKeyDown={
			onChange
				? event => {
						if (event.key === 'Enter' || event.key === ' ') {
							event.preventDefault();
							onChange?.(index);
						}
					}
				: undefined
		}
	>
		{children}
	</div>
);
